func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const inf = 1e18

	nOrders := len(oris)
	orderIDs := make([]int, nOrders)
	for i := 0; i < nOrders; i++ {
		orderIDs[i] = total_ship + i
	}

	// indices of all orders that still need to be assigned
	unserved := make([]int, nOrders)
	for i := 0; i < nOrders; i++ {
		unserved[i] = i
	}

	for len(unserved) > 0 {
		type insertInfo struct {
			orderIdx  int
			bestVal   float64
			bestIdx   int
			secondVal float64
			feasible  bool
		}
		infos := make([]insertInfo, 0, len(unserved))

		// Evaluate every unserved order
		for _, oi := range unserved {
			ori := oris[oi]
			des := dess[oi]
			id := orderIDs[oi]
			best := inf
			second := inf
			bestIdx := -1
			feasible := false

			// trial all existing routes
			for a := 0; a < dispatch.AssignsLen; a++ {
				oldCost := dispatch.Assigns[a].Cost
				if dispatch.Assigns[a].AddShip(id, ori, des) {
					dispatch.Assigns[a].GenRoute()
					newCost := dispatch.Assigns[a].Cost
					delta := newCost - oldCost
					// undo
					dispatch.Assigns[a].RemoveShip(id)
					dispatch.Assigns[a].GenRoute()
					feasible = true
					if delta < best {
						second = best
						best = delta
						bestIdx = a
					} else if delta < second {
						second = delta
					}
				}
			}

			// trial one empty route (future new assign)
			if dispatch.AssignsLen < MAXASSIGNS {
				a := dispatch.AssignsLen
				oldCost := 0.0
				if dispatch.Assigns[a].AddShip(id, ori, des) {
					dispatch.Assigns[a].GenRoute()
					newCost := dispatch.Assigns[a].Cost
					delta := newCost - oldCost
					dispatch.Assigns[a].RemoveShip(id)
					dispatch.Assigns[a].GenRoute()
					feasible = true
					if delta < best {
						second = best
						best = delta
						bestIdx = a
					} else if delta < second {
						second = delta
					}
				}
			}

			infos = append(infos, insertInfo{
				orderIdx:  oi,
				bestVal:   best,
				bestIdx:   bestIdx,
				secondVal: second,
				feasible:  feasible,
			})
		}

		// select order with maximum regret
		selected := -1
		maxRegret := -inf
		for i, info := range infos {
			if !info.feasible {
				continue
			}
			regret := info.secondVal - info.bestVal
			if info.secondVal >= inf-1 {
				// only one feasible position – highest priority
				regret = inf
			}
			if regret > maxRegret {
				maxRegret = regret
				selected = i
			}
		}

		// safe fallback when no order has any feasible position
		if selected == -1 {
			oi := unserved[0]
			ori := oris[oi]
			des := dess[oi]
			id := orderIDs[oi]
			inserted := false
			for a := 0; a < dispatch.AssignsLen; a++ {
				if dispatch.Assigns[a].AddShip(id, ori, des) {
					dispatch.Assigns[a].GenRoute()
					inserted = true
					break
				}
			}
			if !inserted {
				if dispatch.AssignsLen < MAXASSIGNS {
					a := dispatch.AssignsLen
					dispatch.Assigns[a].AddShip(id, ori, des)
					dispatch.Assigns[a].GenRoute()
					dispatch.AssignsLen = a + 1
				} else {
					// force-insert into last route as last resort
					dispatch.Assigns[dispatch.AssignsLen-1].AddShip(id, ori, des)
					dispatch.Assigns[dispatch.AssignsLen-1].GenRoute()
				}
			}
			// remove this order from unserved
			unserved = append(unserved[:0], unserved[1:]...)
			continue
		}

		// commit best regret insertion
		info := infos[selected]
		oi := info.orderIdx
		ori := oris[oi]
		des := dess[oi]
		id := orderIDs[oi]
		bestIdx := info.bestIdx

		if bestIdx == dispatch.AssignsLen {
			// create a new route
			dispatch.Assigns[dispatch.AssignsLen].AddShip(id, ori, des)
			dispatch.Assigns[dispatch.AssignsLen].GenRoute()
			dispatch.AssignsLen++
		} else {
			dispatch.Assigns[bestIdx].AddShip(id, ori, des)
			dispatch.Assigns[bestIdx].GenRoute()
		}

		// remove order from unserved
		for idx, val := range unserved {
			if val == oi {
				unserved = append(unserved[:idx], unserved[idx+1:]...)
				break
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

